insert into beasts (name, description, biome, disposition, category, source) values
('ABYSSAL OGRE', 'Underground. A towering sightless giant with translucent stone-cold skin; dwells in lightless depths, using immense pale limbs to crush intruders and drag them into crushing pressure.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('ABYSSCROWN TUSK-WHALE', 'A larger, more scarred deep-sea Crowntooth with teeth blackened by volcanic vent deposits.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('AEIRHYD', 'Neutral Sea Dragon of Warman’s Lake.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('AETHERIUM GOLEM', 'Aether-aligned construct of white metal, crystal joints, and floating inner rings. Appears only partly present, with portions of its body phasing behind the world.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('ALAMIR HARE', 'A long-eared plains hare prized for its speed and as a food source. Considered good luck to release one if caught alive.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('AMETHYSTWING PACKRAPTOR', 'A Packraptor variant with violet wing-frills used for threat display and pack signaling. Hunts along cliff paths, scree slopes, and mineral-streaked terrain where its coloration blends with stone.', 'MOUNTAIN', 'SMALLER / GAME', 'Beast', 'global'),
('ANOMALOCARIS', 'A prehistoric aquatic apex predator featuring a segmented body, stalked eyes, and barbed grasping appendages used to snatch prey into its circular plate-lined mouth.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('ANUBITAPH', 'A fierce bipedal jackal-like plains predator with long ears, lean muscle, and a hunter''s cunning; feared for stalking the grasslands in disciplined packs. They use weapons like khopesh swords and long square shields.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('APOPHIS', 'Devourer of Light; Titan Cyclops.', 'GREAT TITANS', null, 'Titan', 'global'),
('ARID OGRE', 'Desert. A towering suns-baked giant with cracked sandstone-like skin; can remain motionless for weeks amidst dunes, waiting to crush travelers who mistake its massive form for a weathered rock.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('ASH SERPENT', 'A heat-resistant serpent that inhabits volcanic rock fields. Ambushes prey by emerging from ash drifts. Its scales resist fire damage. Venom causes rapid internal inflammation.', 'VOLCANIC', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('ASHBEAR', 'A broad-shouldered forest bear with ash-grey fur and a territorial temperament. Largely avoids settlements but increasingly displaced by Veinrunner expansion into old-growth timber regions.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Fiend', 'global'),
('ASHDUNE GRAVEBEAK', 'A lean, pale desert strain of the great hammer-billed flightless predator; can go long periods without water by feeding on blood and organ meat.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('ASHEN REVENANT', 'A rare and dangerous undead formed when a highly spiritually significant individual dies in proximity to a collapsed Veyline. Retains memory, intent, and growing intelligence. Unlike standard undead, an Ashen Revenant can form goals. It can make plans. It remembers who it was and has decided what it wants to do about what happened to it. High to Campaign-level threat. The Scribe recommends treating any confirmed Ashen Revenant sighting as a campaign-level event.', 'UNDEAD', null, 'Undead', 'global'),
('AUROX', 'A broad-horned feral humanoid of plain and grove, known for calm strength.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Humanoid', 'global'),
('AWAKENED JADE GARGOYLE', 'A carved jade guardian given predatory animation through corrupted resonance or failed warding rites. Unlike ordinary gargoyles, it remembers the place it was made to protect and may continue enforcing commands long after their meaning has been lost.', 'UNDEAD', 'HAUNTED UNDEAD', 'Humanoid', 'global'),
('BARK SPIDER', 'A palm-sized arachnid that blends perfectly into tree bark. Bite causes localized swelling and mild fever. Not dangerous to healthy adults.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('BASALT OGRE', 'Volcanic. A towering obsidian-skinned titan forged from cooled volcanic rock; body as hard as mountain stone, exudes intense smoldering heat from glowing magma fissures in its joints.', 'THE OGRE EVOLUTION THEORY', null, 'Titan', 'global'),
('BEBELITH', 'A spider-like horror with cruel intelligence, hooked limbs, and a hunger for sanctified flesh. Most often found near desecrated shrines, abandoned temples, or places where protective rites failed. Covers its face with a set of grotesque hands; if it looks directly at a victim they are immediately stunned.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BEHIR', 'A blue-scaled serpentine monstrosity with lightning breath.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BLACKRIDGE DREAD-CROC', 'A monstrous crocodilian with jagged black dorsal ridges and a snout broader than a man is tall; becomes mud, log, shadow, and shoreline before lunging with violence that seems impossible for something so still.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BLACKWOOD APEX-URUS', 'A massive pursuit-predator bear of dense forest with dark greenish-grey fur and natural markings resembling broken script; moves through heavy timber with surprising quiet. Unlike ordinary bears, it runs prey down.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BLIGHTED', 'Any race corrupted by Dybuk influence, Void contamination, Maelificar shadow, or Apostate resonance.', 'HUMANOID THREAT LINEAGES', null, 'Fiend', 'global'),
('BLINDPLATE MAW', 'A pale, eyeless armored cave fish guided by vibration; haunts flooded caverns and strikes at anything that disturbs the water.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('BLUEWHORL SAWSPIRAL', 'The open-water strain of Sawspiral; slate-blue, follows wounded whales and fishing fleets.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('BLUEWRITHE SERPENT-WHALE', 'The common open-sea strain; its calls travel through hulls like distant thunder.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BOGLURKER', 'A submerged predator that stays perfectly still beneath the muck; uses vine-like feelers to ensnare the legs of those crossing the water.', 'MARSH / SWAMP', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('BONE CONSTRUCT', 'Deliberately assembled undead created through Magister or Necromancer intervention. Require an active will to maintain animation. Medium threat alone; campaign-level threat in organized groups under intelligent command.', 'UNDEAD', null, 'Undead', 'global'),
('BOUNTY CREW', 'Licensed or unlicensed individuals hunting a specific target. Professional, focused. Medium threat.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('BRAMBLEHORN TITAN-HOPPER', 'A darker, shorter-limbed forest strain of Titan-Hopper; males grow small antler-like brow spurs used in mating clashes.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Titan', 'global'),
('BRAMBLEHOUND', 'A disorienting woodland stalker that leads prey in endless looping trails, its shifting fur and misleading scent causing travelers to walk willingly into ambushes.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BRIARDREID', 'A massive root-bound predator that drags prey into the deeper timber.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BRINDLE CATTLE', 'A broad-framed semi-wild bovine of the grasslands, domesticated in most provinces but found feral along frontier roads. Their stampedes have derailed at least two Veinrunner freight loads in recorded history.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('BRINDLECALF', 'A small sure-footed grazer of meadow and brush, known for its gentle nature.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('BRINECROWN TUSK-WHALE', 'The surface-hunting strain; follows whale pods and fishing fleets, attacking where blood and noise gather.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BRINEPLATE MAW', 'A broad dark-blue ocean Ironplate Maw that patrols reefs and shipwrecks.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BRINESICKLE SCYTHE-SHRIMP', 'A blue-grey reef-channel Scythe-Shrimp that follows larger predators to feed on scraps.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('BUMBLEBRUIN', 'A fuzzy bee-bear of meadow and grove, known for gathering nectar.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('BURDEN GOLEM', 'Weight-aligned construct of lead, black granite, dense iron, and pressure-runes. The ground buckles under it even when it stands still, and enemies nearby feel their own bodies become heavier.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('CAIRNWOLF', 'A mountain sentinel that lies motionless among stone piles and cairns, erupting into motion to trigger rockslides and crush isolated prey.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('CANIVINE', 'A woodland hound wreathed in creeping vines and thorned jaws, known for silent stalking and sudden vicious lunges. Can creep into cities.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CANIVINE (URBAN)', 'The same woodland canivine that has followed rail and trade roads into city margins. More cautious than its woodland counterpart. No less dangerous.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CANOPY APE', 'A large, sociable primate of the upper jungle. Not aggressive unless young are threatened. Troops of thirty or more are common. Their alarm calls function as a reliable early warning system.', 'JUNGLE / RAINFOREST', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('CANOPY CONSTRICTOR', 'A massive tree-dwelling serpent that drops onto prey from above. Non-venomous. Kills by constriction. Long enough to encircle a draft horse. Prefers large warm-blooded prey and has been known to target sleeping camp groups.', 'JUNGLE / RAINFOREST', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CANOPY RAVEN', 'A large glossy-black bird of the upper forest. Highly intelligent, mimics voices with unnerving accuracy, and is believed by some Pa''morph Kra''ark to be a distant cousin. Considered a trickster omen.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('CANYON HAWK', 'A large territorial raptor of the badlands. Attacks anything that enters its nesting zone without discrimination. Nests are almost impossible to spot from below. A serious hazard to solo travelers.', 'BADLANDS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CAP RAUK', 'Fungal Forest. A mushroom-plumed fungal rauk that slips soundlessly through dim groves and cavern roots; often taken as an omen of damp rot and hidden growth.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('CARAGAR', 'Chaotic Evil Fire Wyrm of Lilith’iel.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('CARRION KITE', 'A large bird of prey that feeds on carrion. Often seen circling above battlefields, waiting for its next meal.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CARRION WINGED KITE', 'A larger variant of the Carrion Kite with broader wings, allowing it to soar higher and cover more ground in search of food. Often arrives at battlefields before standard Carrion Kites and departs last.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CARRION-SAIL CLOUD-VULTURE', 'A vast gas-bladdered battlefield scavenger whose shadow over a road is considered a bad omen by soldiers; its presence in numbers means something has already died nearby or soon will.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CARRIONZELLE', 'A wasteland-dwelling, carrion-feeding gazelle-like creature with ragged horns, blackened hooves, and a taste for battlefield remains. Skittish when alone, but dangerous in numbers.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('CAVE BEAR', 'A massive bear adapted to mountain cave systems. Hibernates during cold seasons. Much larger than the ashbear. Encounters near cave entrances in early spring are extremely dangerous.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CAVE FISH', 'Blind, pale fish found in underground waterways. Primary food source in long underground expeditions. Nutritious and surprisingly easy to catch in still water.', 'UNDERGROUND', 'SMALLER / GAME', 'Elemental', 'global'),
('CAVE MOTH', 'A large pale moth that navigates cavern systems by echolocation. Non-aggressive. Their wing dust causes mild irritation to eyes and airways but is not toxic.', 'CAVERNOUS', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('CAVERN SPIDER', 'A blind cave-adapted spider with a body the size of a large dog. Hunts by vibration. Webs are nearly invisible in darkness and strong enough to hold a struggling human.', 'CAVERNOUS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CAVERNOUS GHOSTCRAB', 'A blind, pale ghostcrab that inhabits underground streams and flooded cavern shelves. Navigates by vibration and retreats into cracks too narrow for most predators to follow.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('CEDAR OGRE', 'Woodland. A towering bark-skinned giant wreathed in living cedar boughs; sentinel of the ancient woods, crushing those who threaten the sanctity of the grove.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('CENTAUR', 'A fierce plains hunter whose speed and pride make it dangerous to cross.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CERULEN', 'Neutral Sea Dragon of the Azure Tides.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('CHAINWAKE SERPENT-WHALE', 'An island-channel Longwrithe that travels predictable routes; island pilots learn its passages the way farmers learn river floods.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CHRONOVORE', 'A time-devouring hunter of the Chronison that consumes stolen years, alternate selves, and forbidden futures.', 'HUMANOID THREAT LINEAGES', null, 'Beast', 'global'),
('CINDER GOLEM', 'Fire-aligned construct of kiln-stone, iron ribs, and furnace-glass veins. Body smolders constantly, shedding ember flakes as it moves; damaged plates expose molten heat beneath the frame.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('CITY CROW', 'The urban equivalent of the canopy raven. Highly intelligent, adaptable, and present in every major Soterian city. Known to steal small objects. Some individual city crows have been observed following specific people for days, apparently by choice.', 'CITY / URBAN', 'SMALLER / GAME', 'Beast', 'global'),
('CLAWSTRUTH RAPTOR-STRUTHIO', 'A feathered pursuit predator with a retractable killing claw; sprints in terrifying bursts, slashes, retreats, circles, and repeats until prey collapses. Packs can bring down riders and livestock.', 'SAVANNAH', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CLIFF ADDER', 'A venomous mountain snake that basks on sun-facing rock faces. Camouflaged against stone. Venom causes rapid cardiac stress in small creatures.', 'MOUNTAIN', 'SMALLER / GAME', 'Beast', 'global'),
('CLOUDSCYTHE MANTIS', 'A high-altitude mantis predator with pale cloud-colored plating and long hooked forelimbs. Clings to cliff faces and mist-wrapped trees, striking from concealment before vanishing into fog.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CLOUDWHALE', 'A vast, gentle aerial creature that drifts at extreme altitude feeding on atmospheric particulates. Rarely seen clearly. Considered a blessing omen by most Soterian cultures. Their passing is accompanied by a low harmonic resonance that spiritually sensitive individuals can perceive as immense calm. - CLOUDRAY - A large, manta ray-like creature that glides through the sky on broad membranous wings. Feeds on airborne plankton and small birds. Non-aggressive and often seen in groups, their graceful flight is considered a symbol of freedom and tranquility. - FAE CLOUDWHALE - A smaller, more colorful variant of the Cloudwhale, adorned with iridescent patterns on its skin. Known for its playful nature and tendency to interact with other flying creatures, it is often seen as a symbol of joy and whimsy in Soterian folklore.', 'SKY', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('COBALT RAUK', 'Grassland. A blue-plumed plains rauk.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('COGDOG', 'A grimforge industrial hound with exposed gears and pistons beneath patchy fur, patrolling rail yards and factories with a clicking, wheezing gait.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Troll', 'global'),
('COMMON FISH', 'Perch, carp, and river trout equivalents found in most Soterian waterways. Primary freshwater food source.', 'RIVER / COASTAL / FRESHWATER', 'SMALLER / GAME', 'Elemental', 'global'),
('CORDYCEP HOUND', 'A wolf-sized creature overtaken entirely by a parasitic fungal organism. The original animal is dead; the fungus animates the body with surprising tactical coordination. Attacks in silence. Produces spores on death that can begin the same process in living hosts over several days.', 'FUNGAL FOREST', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CRADLECRAG BOULDER-WOMBAT', 'A mountain strain of Boulder-Wombat with thicker hide and stone-dusted shoulder plates; often mistaken for fallen boulders during fog.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('CRAG RAUK', 'Cavernous. A sharp-beaked ash-colored rauk that dwells in lightless cavern hollows; navigates through densest stalactite forests by emitting a low-frequency hum that echoes off stone.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('CRAG-RUNE APEX-URUS', 'A mountain strain of the great Runebear with dark brown or slate fur and heavier forelimbs for climbing broken slopes; notorious for appearing above travelers rather than behind them.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CRAGSPOT SKY-NECK', 'A colossal cliff-nesting pterosaur with a giraffe-long neck and mottled grey-rust hide; uses its reach to pluck prey from ledges and ruins without committing its full body to danger.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CRAGWING RAZORGALE', 'A lean mountain pterosaur specialized in knocking prey from ledges rather than carrying them away; nests in sheer cliff cracks and is nearly invisible against stone.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CRIMSON RAUK', 'Woodland/Highland. A scarlet-plumed highland rauk that rides the wind like an omen, known for its piercing cry and watchful circles above the forest trees.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('CROWNTOOTH TUSK-WHALE', 'A predatory whale armed with massive crown-like ivory fangs in both jaws; actively hunts giant squid, lesser whales, sea serpents, and ships that resemble wounded beasts.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CRYOGRE', 'Tundra. A massive frost-rimed titan whose skin is a patchwork of permafrost and jagged ice; can freeze the very air with its breath before shattering paralyzed prey with a single earth-shaking blow.', 'THE OGRE EVOLUTION THEORY', null, 'Titan', 'global'),
('CRYPTID', 'A skulking woodland creature known for unnatural cunning, sudden violence, and half-glimpsed shapes between the trees.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('CULT ENFORCERS', 'Armed operatives of any of Soteria''s active cult structures (the Verdant Spiral, the Harrow-adjacent practitioners, the Stonecutter Clan, etc.). True believers are more dangerous than mercenaries. Medium-to-High threat.', 'FACTION THREAT GROUPS', null, 'Humanoid', 'global'),
('DART FROG (SOTERIAN)', 'A brilliantly colored small amphibian whose skin secretes a potent contact toxin. Collected by Brunar traders for poison applications. Handling without protection is strongly inadvisable.', 'JUNGLE / RAINFOREST', 'SMALLER / GAME', 'Beast', 'global'),
('DEEP CRAWLER', 'A multi-legged pale predator of the lightless underground. Hunts by vibration detection. Extremely sensitive to sound; loud noises cause disorientation. Produces a faint bioluminescent slime trail. Medium threat in confined tunnels.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('DEEP WHALE', 'A massive cetacean of the open ocean. Non-aggressive. Their resonance signatures are among the most stable natural phenomena in Soteria. Wyth scholars believe deep whales function as passive anchors for oceanic Veyline stability.', 'SUBAQUATIC / OCEAN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('DEEPPLATE ARMOR-CRAWLER', 'A blind, pale-bellied cave strain of Platewyrme with dark-above, chalky-beneath plating; silent on stone and devastating in confined tunnels.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Dragon', 'global'),
('DEPOT MOUSE', 'A clean, surprisingly healthy rodent variant found exclusively in Veinrunner depot grain stores. Has developed immunity to most standard rodent deterrents. The depot workers have largely given up and named several of them.', 'INDUSTRIAL / VEINRUNNER ERA', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('DESERT GHOSTCRAB', 'A sand-pale ghostcrab that burrows beneath dune crusts and dry salt flats. Emerges at night to scavenge insects, lizards, and carrion.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('DESERT LIZARD', 'A common agile lizard of dry regions. Edible. Considered a survival food staple. Some species are mildly venomous.', 'DESERT', 'SMALLER / GAME', 'Beast', 'global'),
('DESERT TORTOISE', 'A slow-moving armored reptile of arid regions. Extremely long-lived. Some individuals are believed to carry resonance impressions from centuries past. Considered sacred in certain Ahnkir traditions. Harming one is considered deeply poor judgment.', 'DESERT', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('DIAMOND RAUK', 'Arctic. A crystalline translucent-plumed rauk that refracts the light of the three suns into dazzling prisms; a brilliant yet cold omen above frozen wastes.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('DOCK BIRD', 'Common large seabird of port districts. Aggressive around food but not genuinely dangerous. Their alarm calls have alerted more than one dockside guard to intruders.', 'CITY / URBAN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('DRAEKUL', 'A corrupted Drakazir bloodline driven by hoard-lust, bloodfire, ancient tyranny, and draconic supremacy.', 'HUMANOID THREAT LINEAGES', null, 'Elemental', 'global'),
('DRAUGR', 'A grave-bound undead or Rootwraught horror associated with burial sites, cold memory, and violent refusal to remain dead. Often found near old barrows, battlefield graves, frozen ruins, and places where the dead were not properly witnessed.', 'UNDEAD', null, 'Undead', 'global'),
('DROWNED', 'A specific Echoing undead type found near significant water features where drowning deaths have occurred in numbers. Semi-aquatic. Slower on land. Extremely dangerous in water. Resonance: Echoing.', 'UNDEAD', null, 'Undead', 'global'),
('DRYT', 'A shy woodland spirit that tends roots, streams, and wounded trees.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('DUERGAR', 'A deep-forge Durinak counterlineage hardened by buried spite, cruel industry, and the black pressure of the underworld.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('DUNECLAW RAPTOR-STRUTHIO', 'A pale-feathered desert pursuit predator that hunts at dawn and dusk when shadows make its sprint harder to read.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('DUNEFLASH SUNSAIL', 'A desert strain of Sunsail Skink with orange, rust, and gold sail markings; buries itself under sand at night and emerges at dawn.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('DUNEHEEL TITAN-HOPPER', 'A pale-furred desert strain of Titan-Hopper with wide heat-shedding ears and an efficient stride capable of crossing salt flats that kill horses.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Titan', 'global'),
('DUNESTRIDE SKY-NECK', 'A pale-hide narrow-winged desert pterosaur with a heat-shedding throat pouch; stalks dry washes and ancient roadways waiting for exhausted creatures to slow beneath its shadow.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('DUNEWOLF', 'A desert pack hunter whose sand-colored fur and flattened silhouette make it nearly invisible until it erupts from dunes in a storm of teeth and dust.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('DUNSHRIKE', 'A lean, long-legged plains grazer.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('DUSTMOUND BOULDER-WOMBAT', 'A plains strain that digs wide, shallow tunnel networks; disliked by ranchers whose livestock break legs in old burrow roofs, but valued by farmers for soil-turning.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('DUSTRAT', 'A small scrubland rodent with quick paws and sharp instincts; known for burrowing beneath dry earth.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Elemental', 'global'),
('DYBUK', 'A shadow-born entity of shifting form that feeds on fear, grief, and despair; grows more real and dangerous wherever suffering lingers. Nature: Born from the Void (Tophet). No physical bodies; they require a host. Drawn to individuals in states of spiritual vulnerability: grief, humiliation, envy, failure, obsession, despair, broken oaths, abandoned faith, or lost Veyline alignment. On Nazros their feeding behavior is industrialized (Operation Trust). In Soteria, they operate individually or in small clusters. Conditions increasing manifestation risk: mass grief, betrayal, unresolved trauma, isolation, false Nullite exposure, collapsed faith structures, prolonged silence, abandoned settlements, and corrupted Veylines. Conditions reducing manifestation risk: genuine communal trust, active Sanctus practice, truthful witness, functioning Veylines, emotionally stable populations, and dawn-aligned ritual activity. Feeding: Dybuks feed on live despair — not death itself, but the sustained experience of loss while still alive. A Dybuk will often keep a host functional while harvesting suffering rather than simply killing them. Possession signs: Discoloration of veins, coldness of skin, eyes that reflect light incorrectly, uncharacteristic calm followed by sudden violence. Weaknesses: True spiritual alignment, Sanctus discipline, Caelyn pact-bonds, genuine Nullite, sunlight during Ba''el (Dawn pass). Strengths: Isolation, silence, false Nullite, broken oaths, grieving spaces. Threat Level: Medium solo / High when possessing a powerful or named NPC / Campaign-level when organized. Combat behavior: A Dybuk fights using the host''s memories, abilities, and relationships — it will exploit all of them. It targets witnesses and allies first to isolate the party. Avoids direct confrontation with Divine-aligned characters. If the host body is destroyed, the Dybuk is expelled but not destroyed — it seeks a new host immediately. True destruction requires a Caelyn severing the Veyline connection, a Sanctus exorcism, or a binding ritual returning it to Tophet.', 'COSMIC / VOID / ASTRAL', 'AGGRESSIVE / PREDATORY', 'Fiend', 'global'),
('DYBUK-HOST (LATE STAGE)', 'When a Dybuk has occupied a host long enough, the host body begins to physically change. Veins blacken visibly. Temperature drops measurably. The host''s original personality is effectively consumed. The host cannot be saved through conventional means. Resonance: Void-Tainted. High threat.', 'UNDEAD', null, 'Fiend', 'global'),
('ECHOING DEAD', 'A rare form of undead in which the deceased''s resonance impression is so strong that it persists as a semi-autonomous presence. Often found at sites of tremendous emotional significance — last stands, executions, places of profound betrayal. They remember who they were, and that memory makes them unpredictable. High threat. Resonance: Echoing.', 'UNDEAD', null, 'Undead', 'global'),
('EMRYS', 'Neutral Good Imperial Dragon of Verdelie’re.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('FAECOLT', 'A small enchanted horse of glade and grove, known for its speed and gentle temperament.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('FEN OGRE', 'Marsh. A bloated water-logged giant that generates a thick sulfurous miasma from its skin, blinding players while it hunts by vibration.', 'THE OGRE EVOLUTION THEORY', null, 'Elemental', 'global'),
('FERNPUP', 'A soft-coated forest pup known for nesting in fernbeds and befriending lost travelers.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('FERRABORNE', 'A hard-bodied Pa’morph opposite shaped by iron, invasive growth, and anti-natural adaptation rather than living animal harmony.', 'HUMANOID THREAT LINEAGES', null, 'Beast', 'global'),
('FERRUGWORATH', 'A rust-red gorilla creature that seeks out metal and leaves only corrosion behind. Increasingly seen near Veinrunner rail lines where exposed iron is abundant.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('FERRUGWORATH (RAIL VARIANT)', 'The standard Ferrugworath adapted to follow the Veinrunner rail network, attracted by the concentration of exposed iron and steel. Rail variant specimens are larger and more aggressive than plains counterparts. The Veinrunner Authority has an open bounty.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('FETCH DIREBEAK', 'A druidic familiar summon shaped like a large predatory bird, able to appear as crow, raven, hawk, owl, kite, or vulture depending on the druid’s bond. Used for scouting, message-carrying, aerial harassment, and warning calls.', 'DRUIDIC FETCHES', null, 'Beast', 'global'),
('FETCH DIREBOAR', 'A druidic familiar summon shaped like a heavy tusked boar with dense shoulders and stubborn spirit-force. It charges through brush, breaks weak barricades, and defends its summoner with brutal direct aggression.', 'DRUIDIC FETCHES', null, 'Humanoid', 'global'),
('FETCH DIREDRAKE', 'A druidic familiar summon shaped like a small dire drake with rugged scales, clawed limbs, and a low predatory stance. Used for guarding, intimidation, and short-range combat, it fights with snapping jaws and sudden lunges.', 'DRUIDIC FETCHES', null, 'Dragon', 'global'),
('FETCH DIRELIZARD', 'A druidic familiar summon shaped like a rugged dire lizard with clawed feet, a thick tail, and alert reptilian senses. It clings to stone, darts through undergrowth, and fights with quick bites, tail sweeps, and stubborn survival instinct. Ogres are believed to be ancient adaptive megafauna shaped directly by environmental resonance pressure. Unlike ordinary creatures, Ogres exhibit terrain mimicry, environmental synchronization, abnormal durability, and ecosystem-level territorial behavior. Some scholars argue Ogres represent "the same primordial organism repeatedly rewritten by different regions of Soteria." OGRE FAMILY — BIOME VARIANTS:', 'DRUIDIC FETCHES', null, 'Humanoid', 'global'),
('FETCH DIREPARD', 'A druidic familiar summon shaped like a large predatory cat, ranging from lynxlike to pantherlike depending on the summoner’s region. Silent, agile, and precise, it excels at stalking, ambush, climbing, and striking exposed targets.', 'DRUIDIC FETCHES', null, 'Beast', 'global'),
('FETCH DIRERYU', 'A druidic familiar summon shaped like a floating serpentine ryū, called from wind, mist, leaf-spirits, or old river resonance. Graceful and watchful, it scouts from above, coils through the air, and lashes at threats with a spectral bite or tail-strike.', 'DRUIDIC FETCHES', null, 'Elemental', 'global'),
('FETCH DIRETOAD', 'A druidic familiar summon shaped like an oversized swamp toad with slick hide, springing legs, and a wide gripping mouth. It leaps suddenly, clings to enemies, and can harry foes with croaks, slime, or minor toxic secretions.', 'DRUIDIC FETCHES', null, 'Beast', 'global'),
('FETCH DIREWARG', 'A druidic familiar summon shaped like a twisted grim-warg with a low body, heavy jaws, and cruel hunting instincts. More aggressive than the Direwolf Fetch, it excels at pursuit, fear tactics, and dragging enemies off balance.', 'DRUIDIC FETCHES', null, 'Beast', 'global'),
('FETCH DIREWOLF', 'A druidic familiar summon shaped like a larger-than-natural wolf with spirit-bright eyes and bristling fur. Loyal, fast, and tactically aware, it tracks enemies, guards camps, and helps bring down prey through coordinated bites.', 'DRUIDIC FETCHES', null, 'Beast', 'global'),
('FIELD CROW', 'Common black bird of open country. Highly adaptable, found near settlements, farms, and rail depots. Considered a pest in most agricultural provinces.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('FLAKE RAUK', 'Tundra. A pale downy-feathered rauk that blends perfectly into falling snow; a silent omen of approaching frost or a guide for those lost in blizzard white.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('FOG-O-WAR', 'A jellyfish-like cicada horror that gathers where fear, smoke, and unresolved violence linger. It manifests as a low crawling fog filled with half-seen limbs, muffled commands, and sudden grasping shapes.', 'BADLANDS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('FOREST ADDER', 'A banded venomous snake of the undergrowth. Non-aggressive unless disturbed. Venom causes mild paralysis of the affected limb.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('FOREST GHOSTCRAB', 'A moss-backed ghostcrab found in damp hollows, old wells, and rain-swollen root systems far from the sea. Scribes believe its ancestors followed underground waterways inland and never returned.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Undead', 'global'),
('FRESHWATER TURTLE', 'Common large turtle of river banks and lake edges. Docile. Edible. Their shells are used in a variety of craft applications.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('FROSTMANE SPIRALHORN', 'A massive tundra-adapted beast with a huge spiral horn that bores into frozen ground and bears a crown of ice crystals after feeding; its charge twists rather than simply impales.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('FROSTSHELL GLACIER-TURTLE', 'A colossal ancient sea turtle carrying ice, pale barnacles, and frost algae across its shell; sleeping specimens are mistaken for small ice floes in cold seas.', 'ARCTIC', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('FROSTWRAITH', 'A spectral ice-veined predator that manifests from killing cold; haunts frozen wastes with a chilling touch and silent predatory hunger for the warmth of the living. Related to but distinct from the Whispering Frostwraith of the Falorn Fjords, which is near-Titan scale.', 'TUNDRA', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('FURBACK EURYPTI', 'A broad, many-legged subterranean predator with coarse fur along its plated back and grasping forelimbs adapted for tight tunnels. Waits half-buried in loose stone, then surges forward to seize prey and drag it into narrow cracks.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GALE-RIB GOLEM', 'Air-aligned construct of light wood, silver wire, sailcloth, and hollow bone. Much of its body is invisible pressure and compressed wind, making its strikes difficult to read.', 'GOLEM FAMILY', null, 'Undead', 'global'),
('GARGOYLE', 'A stone-winged city predator that lurks upon rooftops and spires; strikes intruders with sudden claws and brutal silence.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GASBLOOM CLOUD-VULTURE', 'A vast floating scavenger with a gas-filled throat pouch that allows near-wingless drifting over battlefields; releases a rotten flammable belch when startled, strong enough to sicken horses.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GENIE', 'A dangerous true wish-being whose bargains bend desire into debt, servitude, elemental punishment, or ruin.', 'HUMANOID THREAT LINEAGES', null, 'Elemental', 'global'),
('GLACIAL GHOSTCRAB', 'A translucent ice-shelled crab that nests in cracks beneath glaciers and frozen coastal shelves. Its body is nearly invisible against blue ice, and its claws can numb exposed flesh with prolonged contact.', 'ARCTIC', 'DOCILE / FRIENDLY', 'Undead', 'global'),
('GLASS PHARAOH', 'A Titan-Shed construct of fused desert glass and ancient bone that believes itself the ruler of all sand. It "taxes" travelers by extracting water and memories.', 'DESERT', 'DOCILE / FRIENDLY', 'Titan', 'global'),
('GLASSWING STEELNEEDLE', 'A translucent-winged coastal strain that nests near tide pools; feeds on seabirds, crabs, and stranded fish before turning on larger prey.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GLIMROOT', 'A sentient glowing root-system that entangles intruders.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('GLOAMWING', 'A large bat with wings that shimmer like the twilight sky. Nocturnal, feeds on insects and small mammals.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GLOOMWHORL SAWSPIRAL', 'A dark, slow, nearly blind deep-sea Sawspiral with pale sensory pits; its tooth-whorl may glow faintly from deep-sea organisms caught between the blades.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GLOW WORM', 'A small bioluminescent larva found in cave ceilings in large colonies. Their combined light is sufficient to navigate by. Harvested and used in small lantern capsules by underground workers.', 'UNDERGROUND', 'SMALLER / GAME', 'Beast', 'global'),
('GLOWCAP', 'A soft bioluminescent fungus-creature that gathers in damp groves and cavern roots.', 'FUNGAL FOREST', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('GLOWHORN PALEHIDE', 'A subterranean drill-rhino strain with pale skin, poor eyesight, and a faintly bioluminescent horn; when the hornlight appears in a tunnel, the safest path is usually backward.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GOBLIN', 'Small cunning humanoids known for scavenging, ambush tactics, and crude ingenuity. Goblin tribes dwell in hidden woodland dens, abandoned ruins, tunnel systems, and scrap settlements near older trade roads. Though physically weak individually, they become dangerous in coordinated numbers.', 'SYLVAN GROVE', 'SMALLER / GAME', 'Humanoid', 'global'),
('GOLDGRASS GRAVEBEAK', 'A towering flightless predator with a sledgehammer beak and a curved killing point; the classic man-killer strain of open savannah, often seen as a dark shape cutting through high grass before the head drops like a smith''s hammer.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GOLDPLUME CLAWSTRUTH', 'A feathered ostrich-like predator with a retractable killing claw on each foot; hunts in loose packs using dust clouds to confuse prey, fast enough to overtake a horse over short ground.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GOLDSTEP TITAN-HOPPER', 'The most common strain of Titan-Hopper, featuring wheat-colored fur and strong migratory instincts. Its herds move like living weather across open country.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Titan', 'global'),
('GORJACK', 'A brutal grassland hunter that bounds through thorn and reed, notorious for dragging down larger prey with hooked jaws.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GRAFTWRIGHT', 'A predatory falsework creature that grafts itself into objects, rooms, and structures, taking the form of what victims expect to find before latching, swallowing, or absorbing them. Often mistaken for chests, doors, shrines, books, tools, wagons, or relics. Older specimens can become part of an entire room.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GRANULE PACKRAPTOR', 'A dust-colored Packraptor with rough pebble-like scales along its spine and shoulders. Often rolls through loose soil to mask its scent before ambushing prey.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GRASSLAND ADDER', 'A thick-bodied venomous snake that basks on sun-warmed stones and road surfaces. Responsible for more traveler injuries than any predator in the province records.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('GRAVEBEAK HAMMER-BIRD', 'A towering flightless predator with a sledgehammer beak and a curved killing point; measures its target before the head drops like a smith''s hammer. Nests are shallow ground-scrapes lined with bones, hide scraps, and bright stones.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('GRAVEMASS GOLEM', 'Earth-aligned construct of packed clay, stone, root, bone fragments, and buried metal. Moves like a walking hill torn from an old battlefield, reshaping terrain as it advances.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('GREATER DESERT SCORPION', 'A man-sized scorpion of rocky desert terrain. Venom causes paralysis within minutes. Hunts at night. During the day they shelter beneath rock overhangs and in ruins; the same places travelers seek shade.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GREATER GRAFTWRIGHT', 'A more powerful version of the Graftwright with stronger ability to integrate into and control its surroundings. Often found in more complex or elaborate structures.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GREATER JACK PACKRAPTOR', 'A larger and more formidable Jack Packraptor variant with thicker hide, heavier jaws, and dominant pack behavior. Often serves as leader among smaller Jack packs.', 'PACKRAPTOR FAMILY', null, 'Beast', 'global'),
('GREATER PACKRAPTOR', 'A large alpha-class Packraptor capable of leading mixed packs across plains, scrublands, and badland edges. Heavier frame makes it less agile than smaller variants but far more dangerous once it closes distance. 16. WASTES (CHRONOLITHE & CHEMICAL)', 'BADLANDS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GREENMANE MAWLOAM', 'A common woodland strain of Mawloam armored in wiry fur layered with moss, lichen, and burrs; elder specimens may be mistaken for hillocks until their heads lift from undergrowth.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('GREY RAUK', 'Badlands. A medium-sized mottled grey-feathered rauk with a heavy dust-coated beak; perches on barren rock within vast parched canyons.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('GREY WOLF (SOTERIAN)', 'The common wolf of Soteria''s forests and hills. Larger than expected, pack-coordinated, and known to avoid Dybuk-touched territory entirely. Hunters read wolf absence as a spiritual warning. Pack sizes range from four to sixteen.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Fiend', 'global'),
('GRID WRAITH', 'A Glyphic resonance entity that has formed around a damaged or overloaded Grid conduit node. Manifests as visible electrical discharge with apparent will and targeting behavior. Attacks anything conducting electricity or resonance. Cannot be negotiated with. Disrupted by grounding and genuine Nullite. Resonance: Glyphic.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('GRIMRITE BEETLE', 'A large subterranean insect whose carapace has partially crystallized from generations of grimrite exposure. Mandibles can penetrate standard leather armor. Found in collapsed mine sections and near raw grimrite veins. Resonance: Grimrite-Saturated.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GRIMRITE POACHERS', 'Illegal grimrite extraction crews. Armed. Paranoid. Willing to use violence to protect their operation. Medium threat.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('GRIMRITE WOLF', 'A grey wolf pack that has inhabited a mine collapse zone long enough for grimrite saturation to partially crystallize their skeletal structure through their hides. Pack-hunting behavior is unchanged. Their bites can cause minor resonance contamination in open wounds. Resonance: Grimrite-Saturated. Found near the Corren Mountain Mines and the older Durinak extraction sites.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GRINCOIL', 'A brightly marked arboreal serpent with a pale clown-like face, crimson crown-scales, and a wide painted-looking mouth resembling a cruel grin. Coils around trunks and branches, swaying like a performer before striking. Venom causes disorientation, laughter-like spasms, vivid false colors, and eventual paralysis.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GROTHMOGG', 'A hulking Othrod war-brute shaped by conquest, hunger, tribal cruelty, and relentless battlefield dominance.', 'HUMANOID THREAT LINEAGES', null, 'Beast', 'global'),
('GROVE PRISM-WING', 'A green, gold, and blue forest strain of Prism-Wing whose song mimics woodland birds and running water, making it nearly impossible to locate by ear.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('GROVEKEEPER', 'Sylvan Grove. A large, solemn forest bird regarded as a silent overseer of the deep groves, known for its piercing cry and uncanny awareness of disturbances within ancient woodland regions. Repeated Grovekeeper calls are a warning of imbalance, blight, or nearby predatory movement.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('GRYPHON', 'A proud winged hunter of cliff and sky, known for keen sight and fierce territorial wrath.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GULLY OGRE', 'Jungle. A moss-shrouded giant that lurks in deep ravines and jungle floor depressions, waiting for the Rhinallon to flush prey into its waiting reach.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('GUST RAUK', 'Sky. A slender silver-plumed rauk that rides volatile wind currents of the high sky; harbinger of approaching storms or sudden violent gales.', 'THE RAUK THEORY', null, 'Elemental', 'global'),
('GWOWRATH', 'A hulking grassland predator of brutal strength and bestial cunning, feared for savage charges, crushing limbs, and wild fury.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('GWYLLION', 'A ragged crone appearing as an old woman who misleads travelers with echoing cries, yet may seek hearth and shelter when treated kindly.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('HAEROBURROW', 'A burrowing insectoid predator that tunnels beneath loose soil, rotten roots, or clothing. Can be mistaken for a small plant prickle. Its arrival is often heard before it is seen: a dry scraping beneath the skin. Causes infestations that can last for months before eradicated. Also found in industrial waste zones near processing facilities.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('HARROW PRACTITIONERS', 'Wielders of blood-adjacent or corruption-adjacent magic. Variable threat depending on training. Some are desperate individuals who made bad decisions. Others are deliberate architects of harm.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('HEARTHWOOL SHAGGYSWINE', 'Extremely thick white or cream wool, often kept in cold settlements as a living bedwarmer. Its wool sheds in heavy seasonal clumps and is woven into mitts, boot-liners, and infant blankets.', 'EXPANDED / MISCELLANEOUS', null, 'Elemental', 'global'),
('HEIRESS NAGA', 'A regal serpentine lure-predator with a humanlike upper body and a great constrictor''s tail. Drapes itself across branches, ruined balconies, and river stones like nobility at rest, feigning weakness until prey approaches. Its voice carries a soft commanding resonance that makes victims feel honored before the coils tighten.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('HETH', 'Mount of Death; Titan Dracolith.', 'GREAT TITANS', null, 'Titan', 'global'),
('HIDE OGRE', 'Badlands. A lean hunched giant draped in a grisly patchwork of cured leathers and trophies; possesses supernatural ability to stitch itself into the environment, remaining invisible until it unfurls its heavy skin-bound club for a killing blow.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('HIGHDRIFT CLOUD-VULTURE', 'A high-altitude mountain Cloud-Vulture that rides thin air above glaciers and cliffs, waiting for avalanches, falls, or failed climbs.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('HIGHGLINT PRISM-WING', 'A silver, violet, and pale rose mountain strain of Prism-Wing whose feathers shine brightest in thin mountain air and dawn frost.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('HOARFELL MAWLOAM', 'A pale, frost-furred northern strain of Mawloam with blue-edged teeth from mineral staining; moves silently through snow and vanishes into blizzard banks. Villages warn children never to approach a snow mound with breath.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('HOLLOW', 'A Risen occupied by a minor Void fragment rather than a full Dybuk. More coordinated than standard Risen. Retains basic spatial awareness and primitive targeting. Does not feel pain. Eyes reflect light incorrectly. Resonance: Void-Tainted.', 'UNDEAD', null, 'Undead', 'global'),
('HOLLOW GOLEM', 'Void-aligned construct of black stone, dead glass, and negative space. Parts of its body appear missing, yet those absences strike with terrible force.', 'GOLEM FAMILY', null, 'Undead', 'global'),
('HOLLOWBEAR', 'An ashbear whose interior has been partially consumed by Draethic resonance from a collapsed Veyline. The cavity in its chest glows faintly in darkness. Attacks driven by pain rather than hunger. Resonance: Draethic.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('HOLLOWJAW MARROWCRUNCHER', 'A cave strain of Bone-Cruncher with dark fur, enlarged ears, and a damp echoing call; cave explorers fear its silence more than its cry.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('HOMUNCULUS', 'A small artificially created entity of uncertain origin, occasionally found operating independently in city environments. Intelligence varies widely. The Wyth have not reached consensus on whether they are creatures, constructs, or something else.', 'CITY / URBAN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('HORNBILL RAUK', 'Savannah. A broad-billed savannah rauk with dark plumage and a harsh cry; often seen as a fierce omen along roads, courts, and caravan trails.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('HUSH', 'A radiant woodland spirit seen drifting through deep forest as a quiet guide for the lost, wounded, or worthy. It appears as a small winged humanoid made of soft golden-white light, its body half-formed and weightless, with mothlike or fae-like wings that shimmer like dusted glass. A Hush does not speak aloud; it beckons with gesture, warmth, and the faint pull of calm in the chest. Travelers who follow one often find safe paths, clean water, hidden clearings, or the way out of enchanted woods. To chase, trap, or shout at a Hush is considered ill fortune, for it vanishes from harsh intent and leaves only darkness behind.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('HYR''DELEAUR', 'A small reptilian creature that feeds on dark emotions rather than flesh or plants.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('ICE SEAL', 'A large marine mammal of arctic coasts. Docile and curious. Primary food source for arctic communities. Their fat provides fuel, their hide provides waterproofing, and their presence indicates open water nearby.', 'ARCTIC', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('ICEWRITHE SERPENT-WHALE', 'A pale-scarred cold-water massive sea-serpent; surfaces among ice floes and is often mistaken for a moving ice ridge. When Icewrithes pass, smart captains stay ashore.', 'ARCTIC', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('IFOR', 'Lawful Evil Storm Dragon of Zallakan.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('IJIRIKI', 'A large moose-like beast with ornate branching antlers that resemble carved ivory and old rootwork. Generally peaceful, but territorial during rutting season; its antlers are prized in ceremonial carving and dangerous enough to break shields.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('IMP', 'A small, sharp-featured creature with clever hands and a shrewd secretive nature; often drawn to hidden things and old bargains.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('IRON RAT', 'A tunnel rat exposed to Grimrite runoff in city sewer systems. Larger than normal. Partially mineral-plated. Pack behavior. Resonance: Grimrite-Saturated.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('IRONPLATE MAW', 'A heavily armored fish with bony skull plating and sharpened jawbone blades instead of teeth; rushes, bites, and rams through dock planks and boat hulls.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('IRONWOOD DEER', 'A large stag of the deep forest whose antlers have a faint metallic sheen from grazing near grimrite-adjacent soil. Non-aggressive but capable of dangerous charges when cornered. Primary prey animal for woodland predators.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('ISLEBACK GLACIER-TURTLE', 'A legendary Shellglacier Turtle large enough for seabirds to nest on its shell during long migrations.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('ITHACUHS', 'A towering shaggy megafaunal beast resembling a fusion of mammoth and bear. Generally passive, but territorial males become violently aggressive during mating periods and drought migration.', 'TUNDRA', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('IVORY PACKRAPTOR', 'A pale coldland Packraptor with ivory scales, low posture, and silent pack movement across snow and frozen scrub. Hunting strategy relies on patience, flanking, and driving prey into exhaustion.', 'TUNDRA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('JACK PACKRAPTOR', 'A small, agile pack predator known for coordinated attacks, short bounding leaps, hooked claws, and ferocious mandibles. Though individually manageable, a full pack can bring down prey many times its size through harassment, flanking, and relentless teamwork.', 'PACKRAPTOR FAMILY', null, 'Beast', 'global'),
('JADE PACKRAPTOR', 'A green-scaled Packraptor adapted to highland mountains, wet passes, and dense vegetation. Uses cover and angled terrain to break prey away from groups.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('JADE RAUK', 'Jungle/Rainforest. A green-plumed jungle rauk that glides between canopy shadows; seen as an omen where the rainforest stills beneath its passing.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('JEWEL-BACK SUNSAIL SKINK', 'Brightly colored with emerald, violet, or red sail patterns. Island children consider spotting one before a voyage to be a sign of good luck.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('JUNGLE RAT', 'A large, adaptable rodent found throughout rainforest settlements and river camps. Disease vector. Responsible for several documented supply contamination incidents.', 'JUNGLE / RAINFOREST', 'SMALLER / GAME', 'Beast', 'global'),
('KHAASTA', 'Agile alligator-like reptilian predators with leathery hides; haunt mountainous regions using cunning and pack-hunting tactics to ambush prey along jagged cliffs.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('KHELL SCHISMFORM', 'A rare Khell expression created when one Khellnid receives conflicting caste signals, producing a divided body, fractured instincts, or unstable allegiance. They do not survive in the hive long as they are culled.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELL UNSET', 'A Khellnid that has failed to caste-set and remains in a dangerous transitional larval state, absorbing traits from its surroundings without becoming a stable branch.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELL’XEN', 'A nightmare hive-predator Khell caste born from darkness, corpse-hives, toxic chambers, and predatory hosts. Develops black carapaces, climbing limbs, corrosive blood, and a merciless infestation instinct.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLCHIN', 'A crustacean-insectoid Khell labor caste shaped by salt flats, marsh protein, shell-matter, and industrial contamination. Often exploited as workers, refugees, or quarantine populations, but dangerous when cornered.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLHANAE', 'A massive brute Khell caste formed through heavy host mass, blood-fed war pits, and dominance pressure. Known for immense strength, pack hierarchy, trophies, siege violence, and command through brutality.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLJTA', 'A solitary apex-hunter Khell caste formed through predatory host matter and isolation rites. Known for stalking worthy prey, wearing kill-masks, collecting trophies, and treating the hunt as sacred law.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLNID', 'The blind larval root-form of all Khellkind. Pale, hook-mouthed parasites that read host tissue, memory residue, mineral exposure, and environmental pressure before caste-setting into a mature Khell branch.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLOCH', 'A colony-form Khell caste in which many Khellnid bodies mature into coordinated worm-masses capable of occupying armor shells, dead giants, stone hollows, or siege frames.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLSARII', 'A tall honor-bound Khell warrior caste with backward skull crests, split jawplates, raptorlike legs, and a rigid culture of duel-law, scar-honor, and oath-bound martial houses.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLSKINI', 'A four armed Khell salvage caste shaped by machine ruins, Grid residue, metallic nutrient exposure, and wreckfield survival. Known for scavenging, engineering, raiding, and weaponizing broken technology.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KHELLYUUM', 'A rare priestly Khell caste cultivated in sacred nutrient pools, relic chambers, and ritual wombs. Physically delicate but mentally dangerous, serving as prophets, theologians, manipulators, and brood-rulers.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('KILN MASTIFF', 'A volcanic brute with smoldering hide and forge-glowing jaws that ignites its surroundings, hunting amid ash flows and leaving trails of blackened glass.', 'VOLCANIC', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('KRAG', 'Small, agile, winged creatures with leathery hides that haunt mountainous heights; fierce berserker-like aggression in young males during mating season.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('KRUG', 'A warped Trink counterlineage of squat tool-users, trap-makers, and spiteful scavenger-crafters with a taste for ruin.', 'HUMANOID THREAT LINEAGES', null, 'Beast', 'global'),
('KRULMAW', 'A powerful feline ambusher of tallgrass and brush, known for speed and force.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Humanoid', 'global'),
('LAMASUMERA', 'A fearsome chimera of the open plains with a lion''s body, horned majesty, and a predator''s cunning; dreaded for sudden violence and impossible form.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('LARK', 'A swift, keen-eyed songbird of field and grove, often trained to carry correspondence across great distances.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('LEAPER', 'A smaller leaping frog with powerful hind legs, fly trap mouth, and a habit of attacking from brush, broken stone, or uneven ground. Usually dangerous in pairs or packs rather than alone.', 'WOODLAND', 'SMALLER / GAME', 'Elemental', 'global'),
('LIQUID GRAFTWRIGHT', 'A rare and highly dangerous variant of the Graftwright that can take on a semi-liquid form, allowing it to infiltrate even the smallest cracks and crevices. Its attacks are more unpredictable and difficult to defend against.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('LITHOPHANT', 'A massive stone-skinned grazer whose migrations shape trails and clearings.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('LLEWELL', 'Chaotic Evil Fire Wyrm of Lilith’iel.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('LONGSPOT SKY-NECK', 'A colossal pterosaur with a giraffe-long neck that browses high leaves and swallows smaller animals whole when opportunity presents; strikes downward from ledges without fully committing its body to danger. Does not chew. Decides.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('LONGWRITHE SERPENT-WHALE', 'A sixty-foot whale with serpentine motion; not interested in people, which is the only reason people still cross its waters. A surfacing Longwrithe can capsize small vessels without noticing.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('LYONOL', 'A majestic six-legged feline predator with a mane of coarse quill-like fur that bristles with static energy; pounces with the weight of a lion and the shocking speed of a lightning strike.', 'BADLANDS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('LYRWISTAG', 'A majestic forest stag with luminous glowing antlers; serves as a silent guardian of Sylvan Grove''s deepest secrets.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('MAL’AKH', 'A fallen Seraphan counterpart of false light, merciless judgment, and divine authority stripped of compassion.', 'HUMANOID THREAT LINEAGES', null, 'Beast', 'global'),
('MANTICORE', 'A proud leonine beast with barbed tail and keen cunning; often found as a fierce but honorable guardian of roads, courts, and caravans.', 'SAVANNAH', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MARROWJAW BONE-CRUNCHER', 'A night-roving scavenger-predator with jaws shaped like iron bolt-cutters; leaves almost no evidence after feeding. A battlefield visited by Marrowjaws may be mistaken for a clean burial ground until one notices the absence of bones.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MARSH CROCODILIAN', 'A large armored ambush predator of swamp waterways. Patient, powerful, and capable of explosive speed over short distances. Rolls prey to disorient before dragging under.', 'MARSH / SWAMP', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('MARSH LEECH (GIANT)', 'A forearm-length blood-feeding worm that attaches painlessly. Commonly encountered when wading through still water.', 'MARSH / SWAMP', 'SMALLER / GAME', 'Elemental', 'global'),
('MARSH TURTLE', 'A large freshwater turtle of muddy banks and slow rivers. Docile unless cornered. Their shells are used in Matekwan ceremonial percussion.', 'MARSH / SWAMP', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('MASSIF OGRE', 'Mountain. A colossal crag-fleshed titan whose stone-like skin is indistinguishable from cliff faces; triggers devastating rockfalls before stepping out to crush intruders.', 'THE OGRE EVOLUTION THEORY', null, 'Titan', 'global'),
('MAULWASP', 'A colossal winged predator of ridge and wildwood, feared for venom and fury.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MAWLOAM', 'See Woodland entry. // DIREFETCH - Direfetch Fae, Direfetch Fae are stored on the face of a Fetchcoin, which a Direwarden will use to summon them. They are small, winged, and often mischievous creatures that can be used for various purposes, such as scouting, delivering messages, or even minor combat assistance. -', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('MEREPLATE MAW', 'A smaller but more aggressive lake Ironplate Maw with green-black armor that claims submerged ruins as territory.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MERESICKLE SHRIMP', 'A freshwater lake arthropod with broad greenish sickle-claws; a hazard to fishermen cleaning nets by hand in weedy still water.', 'UNDERGROUND', 'SMALLER / GAME', 'Elemental', 'global'),
('MINE RAUK', 'Underground. A coal-black sleek-feathered rauk that navigates lightless veins of the earth; used by miners as a living indicator of oxygen levels and impending tunnel collapses.', 'THE RAUK THEORY', null, 'Elemental', 'global'),
('MINOTAUR', 'A hulking bull-headed hunter with immense strength, sharp instincts, and a territorial nature.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MIRE OGRE', 'Wastes/Marsh. A massive muck-encrusted giant with waterlogged mossy skin; lurks beneath the surface of the marsh, waiting to drag unsuspecting prey into the suffocating depths of the bog.', 'THE OGRE EVOLUTION THEORY', null, 'Elemental', 'global'),
('MIRRORLAKE SERPENT-SWAN', 'The most revered strain, found in clear mountain lakes with silver-appearing feathers at sunrise.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('MISTWOLF', 'A marsh and river predator that dissolves into fog between attacks, rising from still water to drag victims under while they are still conscious.', 'MARSH / SWAMP', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('MOLOCHEAN OPERATIVES', 'Agents of the Molochean Hand. Covert, patient. Some appear as allies until they are not. Medium-to-High threat. Campaign-level if the party has drawn the Hand''s specific attention.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('MOLT RAUK', 'Volcanic. A heat-resistant soot-feathered rauk that thrives amidst volcanic vents; a grim omen when it circles low over areas where the earth is about to rupture and bleed magma.', 'THE RAUK THEORY', null, 'Elemental', 'global'),
('MOLTEN GHOSTCRAB', 'A heat-adapted ghostcrab with a black glass shell veined by dull orange glow. Skitters across cooled lava fields and volcanic shorelines, hiding beneath brittle crust before erupting upward.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('MOONMARROW GOLEM', 'Lunar-aligned construct of moonstone, silver dust, ivory, and reflective lacquer. Its form subtly shifts with moonlight, becoming thin, ghostlike, or crowned with pale radiance.', 'GOLEM FAMILY', null, 'Undead', 'global'),
('MOSQUITO HAWK', 'A swift aerial predator with the body and talons of a hawk combined with membranous wings and a blood-draining proboscis. Hunts marshes, jungles, and humid lowlands in aggressive feeding swarms.', 'JUNGLE / RAINFOREST', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MOSSBACK BOULDER-WOMBAT', 'A squat, heavily built beast that carries green moss, mushrooms, and seedlings in its fur. Druids sometimes follow them to locate healthy old-growth soil.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('MOSSLING', 'A small moss-cloaked woodland creature that scurries through root and stone; known for shy curiosity, nimble root tendrils, and tending forgotten groves.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('MOTHWOLF', 'A silent nocturnal predator with pale dusted fur, moth-like wing structures, and a soft powder-coated thorax. The scales shed from its wings interfere with low-level resonance perception and disorient prey in darkness. Hunts primarily at dusk and beneath dense canopy cover.', 'SYLVAN GROVE', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('MOUNTAIN GHOSTCRAB', 'A strange high-altitude crab found in mineral springs, wet cave mouths, and mist-heavy cliffs. Its shell mimics stone and lichen, making it almost impossible to spot until it moves.', 'MOUNTAIN', 'SMALLER / GAME', 'Undead', 'global'),
('MOUNTAIN GOAT (SOTERIAN)', 'A sure-footed high-altitude grazer capable of navigating terrain that defeats most other creatures. Domesticated variants are used as pack animals in Durinak mountain holds.', 'MOUNTAIN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('MOUNTAIN HARE', 'A white-furred hare of high-altitude terrain. Fast, agile, and a primary food source for mountain predators. Its coloring shifts with the season.', 'MOUNTAIN', 'SMALLER / GAME', 'Beast', 'global'),
('MUDKING DREAD-CROC', 'A river-bend Dread-Croc coated in silt, reeds, and leeches; dominates ferry crossings and vanishes in brown water.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('MUDRAK', 'A slippery iridescent amphibian; hard to catch but the primary food source for the marsh''s larger aggressive inhabitants.', 'MARSH / SWAMP', 'SMALLER / GAME', 'Beast', 'global'),
('MURKHARTHOMEL', 'A colossal deep-sea cephalobeast with crushing jaws, boned tentacles, and reef-like camouflage; feared for dragging ships into the abyss.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Aberration', 'global'),
('MYCID', 'A sentient fungal creature of root and spore, known for quiet patience and a shared communal mind. NOTE: The Verdant Spiral cult (Campaign 3) mirrors Mycid communal mind behavior in its Sporebound corrupted citizens.', 'FUNGAL FOREST', 'SMALLER / GAME', 'Beast', 'global'),
('NÐHÖRH', 'The Cursed; Titan Leviathan.', 'GREAT TITANS', null, 'Titan', 'global'),
('NEREIGILL', 'A dark Nazari counterlineage tied to drowned trenches, black water, predatory currents, and abyssal hunger.', 'HUMANOID THREAT LINEAGES', null, 'Elemental', 'global'),
('NETTLEKID', 'A childlike woodland trickster that never seems to age, known for pranks and fleeting laughter in the trees.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('NIDH', 'The Dreamweaver; Titan Basilisk.', 'GREAT TITANS', null, 'Titan', 'global'),
('NOCRAT', 'A nocturnal owl-rat of unusual size and cunning, known for chewing through packs, ration crates, leather straps, and exposed wiring. Swarms are a serious threat to sleeping camps and isolated rail outposts.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('NOCTARYNN', 'A dark, astral-skinned bloodline found across many races and creatures. Noctaryn-born are often unable to speak, leaving them isolated, feared, and easily controlled by stronger factions. Their strength, silence, and violent conditioning have made them prized as hunters, assassins, and shock troops. The Othrod have used them most brutally, leading thousands of Noctaryn into battle against rival clans. //Khell lineages', 'HUMANOID THREAT LINEAGES', null, 'Troll', 'global'),
('NYX''RAXIS', 'A colossal serpentine Void entity formed from living shadow and fractured resonance. Its body appears partially intangible, coiling through darkness like liquid smoke while crimson eyes burn within its shifting silhouette. Associated heavily with Khoneus worship and regions experiencing severe Veyline corruption.', 'COSMIC / VOID / ASTRAL', 'AGGRESSIVE / PREDATORY', 'Fiend', 'global'),
('OAKEN WOODSPIDER', 'An arachnid with a wooden body and branch-like legs that blends into forests.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('OGRE', 'A massive Terraxian counterform warped into brutal adaptive megafauna, using terrain, strength, and endurance to crush intruders.', 'HUMANOID THREAT LINEAGES', null, 'Humanoid', 'global'),
('ONI', 'A towering Helianth counterform marked by demonic appetite, horned brutality, and predatory delight in fear.', 'HUMANOID THREAT LINEAGES', null, 'Fiend', 'global'),
('OPHIDIAN HAND', 'A deeply unsettling serpent-bodied predator ending in two red humanoid palms fused at the wrist. At the center of the palms rests an eye that splits open into a feeding mouth when prey is seized. Believed connected to early Void contamination events or failed Darkweaving experiments.', 'SYLVAN GROVE', 'AGGRESSIVE / PREDATORY', 'Fiend', 'global'),
('ORC RAUK', 'Wastes. A medium-sized sleek-feathered rauk with deep moss-green plumage that reflects the damp shadows of ancient forest.', 'THE RAUK THEORY', null, 'Humanoid', 'global'),
('ORRILLACONDA', 'A massive nightmare hybrid featuring the powerful upper torso of a silverback gorilla fused to the immense muscular coils of a titanoboa; can swing through canopy or constrict prey with terrifying speed. - ORILlACONDACHNID - a massive nightmare hybrid featuring the upper torso of a silverback gorilla with five additional arms spawning from it''s spine on either side, making it eleven arms and the coil of a terrifying titanboa. The additional arms are covered in a chitinous exoskeleton and end in razor-sharp claws, allowing it to grapple multiple prey simultaneously while constricting with its powerful coils. It is an apex predator of the jungle, feared for its relentless hunting tactics and ability to take down large prey with ease.', 'JUNGLE / RAINFOREST', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('OSSYRENTH', 'The Malevolent; Titan Minotaur.', 'GREAT TITANS', null, 'Titan', 'global'),
('OTHRITAUR', 'A towering twelve-foot-tall hybrid of a hellmount horse and an orc; muscular armored behemoth that charges through volcanic ash, designed for high-impact shock warfare.', 'VOLCANIC', 'AGGRESSIVE / PREDATORY', 'Humanoid', 'global'),
('OYAMMOTH', 'A towering prairie elephant with sweeping tusks and thunderous gait.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('PAINTED GRAVEBEAK', 'A smaller island strain of the hammer-billed flightless predator with bright island plumage; more territorial than mainland strains, especially during nesting season.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('PANOPTES', 'The All-Seeing Horror; Titan Beholder.', 'GREAT TITANS', null, 'Titan', 'global'),
('PEAK RAUK', 'Mountain. A high-altitude slate-plumed rauk that rides powerful thermals; viewed by climbers as a sentinel marking the safest passage through treacherous heights.', 'THE RAUK THEORY', null, 'Beast', 'global'),
('PEARLHAVEN SERPENT-SWAN', 'A pearl-white island strain whose nesting pair is considered a sign that waters are clean and fish will return.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('PETALMAW', 'A large deceptive floral predator whose open jaws resemble layered blossoms. Waits among dense flowers or root-choked groves, releasing a sweet scent before snapping shut on birds, small beasts, or careless hands.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('PIXIE', 'Small fey-like woodland entities with luminous wings and mischievous temperaments. While often playful and curious, Pixies possess a manipulative streak and delight in leading travelers astray through illusion, false lights, and altered paths. Their behavior ranges from harmless mockery to dangerous cruelty depending on mood and territory.', 'SYLVAN GROVE', 'DOCILE / FRIENDLY', 'Fey', 'global'),
('PLAINS GIRAFFE (SOTERIAN)', 'A towering long-necked grazer of open savannah. Non-aggressive. A kick from an adult is lethal. Herds of twelve to twenty common near watering sources.', 'SAVANNAH', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('PLAINS HORSE (SOTERIAN)', 'The common wild horse of Soteria''s open country. Herd-living, fast, and difficult to approach without proper training. Domesticated variants are the primary mount across most of the continent. Feral herds are legally protected in Veridoran territory.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('PLAINS HOUND', 'A lean, long-legged dog breed developed by Brunar traders for coursing prey across open ground. Loyal, fast, and poorly suited for cold weather.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('PLAINS VULTURE', 'A large carrion bird that circles dying creatures and fresh battlefields. Non-aggressive unless feeding is interrupted. Their presence in numbers reliably indicates recent death within a half-mile radius.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('PLATEWYRME ARMOR-CRAWLER', 'A long, many-legged arthropod covered in overlapping plates as hard as worked armor; reactive rather than aggressive, lashing out when disturbed during molting or torchlight exposure. Even dead segments can twitch for hours.', 'UNDERGROUND', 'AGGRESSIVE / PREDATORY', 'Dragon', 'global'),
('POLAR STALKER', 'A massive white-furred predator of the arctic ice flats. The largest natural land predator in Soteria outside the ogre family. Hunts alone. Extraordinarily patient; will follow prey for days before attacking.', 'ARCTIC', 'AGGRESSIVE / PREDATORY', 'Humanoid', 'global'),
('PRAIRIEHOLLOW', 'Grassland. A grass-armored plains guardian that crushes intruders.', 'THE OGRE EVOLUTION THEORY', null, 'Undead', 'global'),
('PRIDE LION (SOTERIAN)', 'Larger than natural lions, with a resonance sensitivity that makes them instinctively avoid Dybuk-touched areas. Prides of eight to twelve. Apex predators of open savannah.', 'SAVANNAH', 'AGGRESSIVE / PREDATORY', 'Fiend', 'global'),
('PRISM-WING', 'A small feathered saurian with layered feathers that shift color in sunlight; prized in noble aviaries across Soteria, a rare specimen can be worth more than a trained horse. When frightened, erupts into sudden color and sound to confuse predators.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('PROSOPON', 'A child-sized masked humanoid horror whose face is never seen directly. Mimics gestures, voices, and expressions stolen from others, often appearing first as someone familiar before the mask''s false emotion begins to crack. - PROSPON ACOLYTE - A smaller, more agile version of the Prosopon that serves as a scout and harasser for larger Prosopon. It can mimic voices and gestures but is less convincing than the main Prosopon, making it more likely to be detected before it strikes.', 'UNDEAD', 'HAUNTED UNDEAD', 'Humanoid', 'global'),
('PROVINCIAL GUARD', 'The legal military authority of a given province or city-state. Heavily armed. Backed by infrastructure. High threat if fully mobilized against the party.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('QUAGGA', 'A subspecies of plains zebra with distinctive stripes on its front fading into solid chestnut; primary hardy grazer for the great predators of the grasslands.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('RAGWOLD', 'A rag-wrapped doll-shaped horror that drags itself through abandoned homes, nurseries, and plague houses. It steals warmth from rooms before attacking, leaving victims stiff, silent, and wrapped in their own torn bedding.', 'UNDEAD', 'HAUNTED UNDEAD', 'Beast', 'global'),
('RAIL PIRATES', 'Organized criminal groups that target Veinrunner freight. More sophisticated than road brigands — they have inside information and timing knowledge. Medium threat.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('RAIL WRAITH', 'A Draethic resonance entity that has formed along a section of collapsed or abandoned Veinrunner track where a significant death occurred. Causes disorientation, auditory hallucinations of train sounds, and increasing Dybuk vulnerability in those who linger. Resonance: Draethic.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('RAVENEIR', 'A towering raven-hawk humanoid with layered slate-black feathers, scaled talons, a hooked executioner’s beak, and crescent arm-blades. Raveneirs haunt ruined temples, tomb roads, and old stone gates, standing as silent wardens until trespassers cross too far.', 'UBIQUITOUS / CROSS-BIOME', null, 'Humanoid', 'global'),
('RAZORGALE PTEROSAUR', 'A lean blade-fast pterosaur with cartilage-reinforced wings that cut rough wind; hunts by rising high then folding into steep descents. When the sky goes briefly silent, look up.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Humanoid', 'global'),
('RAZORPACK WOLF', 'A grimrite-saturated wolf whose bones have partially externalized through its hide as jagged mineral spurs. Hunts in packs of three to five. Resonance: Grimrite-Saturated. Found near old mine collapse sites.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('RECLUSE WISKARI', 'Soft blue-beige fur, bright orange markings, enormous black eyes, feather-like antennae between tall bat-like ears.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('REED HERON', 'A tall wading bird of marsh and fen. Non-aggressive. Considered a good omen in Kul''Kal Rakhar territory where their presence indicates clean water nearby.', 'MARSH / SWAMP', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('REED-SAIL SKINK', 'Features blue-green markings and a narrow sail. It dives when threatened and can cling to submerged roots to hide.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('REEDBACK SHAGGYSWINE', 'An oily, water-resistant marsh strain of Shaggyswine that forages along riverbanks for shellfish, reeds, and buried eggs. Smells terrible when wet but nearly impossible to chill.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('REEDCOIL SERPENT-SWAN', 'A tan-and-green river strain less shy than lake variants; sometimes follows boats upstream.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('REEDNEEDLE WASP', 'A green-black river strain of Steelneedle Wasp; fishermen string bells near docks to detect its wing-hum before it strikes.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('REEF GHOSTCRAB', 'A semi-translucent coastal crab that flickers in and out of sight among tide pools, coral shelves, and wreckage-strewn shallows. Ambushes fish, seabirds, and careless hands with sudden snapping claws.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Undead', 'global'),
('REEF SHARK (SOTERIAN)', 'A large, highly territorial shark of coastal reef systems. Attacks boats and swimmers in its territory. Pack behavior around blood or distress in water.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('REEFSHELL GLACIER-TURTLE', 'A Shellglacier Turtle that grows coral gardens and bright anemones; fish shelter around it as though it were a moving reef.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('REEFWATCH SKY-NECK', 'A brighter-mottled island Sky-Neck with broad sea-wind wings; nests on white cliffs and feeds on fish, seabirds, crabs, and anything small enough to vanish in one gulp.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('REEFWHEEL SAWSPIRAL', 'A patterned short-bodied island Sawspiral that hunts reef shelves and wedges itself into coral gaps after prey.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('REVENANT', 'A death-marked being retaining fragments of purpose, anger, memory, or unfinished obligation.', 'UNDEAD', null, 'Undead', 'global'),
('RHIME OGRE', 'Arctic. A hulking rime-crusted giant whose flesh is as hard as glacial ice; immense strength and ability to endure the most brutal sub-zero temperatures.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('RHINALLON', 'A six-limbed behemoth; four legs for sprinting and charging, two upper arms for grasping and forest-clearing.', 'JUNGLE / RAINFOREST', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('RHINDLE', 'A small antlered woodland creature known for skittish movements and uncanny silence.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('RILIK', 'A small cat-like creature known for good luck and fate.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('RIMEJAW MARROWCRUNCHER', 'A thick-furred tundra Bone-Cruncher that caches frozen bones beneath snow and returns to the same buried carcass for months.', 'TUNDRA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('RIMEWILD', 'A pale grassland beast known for swift footing, sharp senses, and a cold wary nature.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('RIMEWING RAZORGALE', 'A pale, narrow-bodied arctic pterosaur nearly invisible against winter skies; wing edges carry frost that glitters just before a dive.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('RISEN', 'The most common undead. A body reanimated by proximity to a strong Echoing resonance source or Void contamination. No intelligence. No memory. Driven by a residual resonance impression. Found near battlefield sites, mass graves, abandoned settlements, and collapsed Veyline zones. Low-to-Medium threat individually. The problem is scale — they cluster. Resonance: Echoing.', 'UNDEAD', null, 'Undead', 'global'),
('RIVER CRAB', 'Common freshwater crustacean. Edible. Pinches. Found under river rocks and along muddy banks.', 'RIVER / COASTAL / FRESHWATER', 'SMALLER / GAME', 'Elemental', 'global'),
('RIVER DOLPHIN', 'An intelligent freshwater cetacean of Soteria''s major river systems. Known to assist drowning travelers. Some Nazari communities maintain working relationships with river dolphin pods.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('RIVER OTTER (SOTERIAN)', 'Large, playful, and surprisingly territorial. Lutra''v Pa''morph consider them distant kin.', 'RIVER / COASTAL / FRESHWATER', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('RIVER PIKE (GIANT)', 'An enormous freshwater predatory fish of deep river channels. Large specimens capable of capsizing small boats.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('RIVER SERPENT', 'A massive non-venomous constrictor of slow-moving rivers and lake margins. Ambushes from underwater. Lengths of six to twelve feet are common. Campaign-level specimens approaching twenty feet have been reported.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('ROAD BRIGANDS', 'Opportunistic criminals operating along trade roads and rail access routes. Lightly armed. Motivated by profit. Will negotiate if cornered and outmatched. Low-to-Medium threat.', 'FACTION THREAT GROUPS', null, 'Beast', 'global'),
('ROCKPIP', 'A small feathered burrower of the high passes with a hooked beak, digging claws, and dense alpine plumage. It hoards vast stores of dried vegetation in its tunnels and is regarded as a sign of good luck by Durinak miners.', 'MOUNTAIN', 'SMALLER / GAME', 'Beast', 'global'),
('ROOF CAT', 'A lean, semi-feral cat population that maintains itself on Ashendell''s rooftops and warehouse districts. Feeds on tunnel rats and dock birds. Considered good luck by dock workers.', 'CITY / URBAN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('ROOST ROC', 'A colossal sky predator feared for its talons and massive beak.', 'WOODLAND', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('ROOT ROC', 'A large bird-like creature with roots for talons that uproots trees in search of prey.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('ROTA', 'Lawful Good Cosmic Omni Dragon; the celestial Omni Dragon whose aurora-like wings span the heavens.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('SABLE-SAND SPIRALHORN', 'A desert drill-rhino with cracked sand-colored hide and a darkened polished horn; charges can collapse old sinkholes beneath itself and everything nearby.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SAFFRONHIDE PACKRAPTOR', 'A dry-country Packraptor variant with yellow-orange hide that blends into sunburnt grass and late-season plains. Hunts in loose packs using stillness and sudden bursts of speed.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('SALTJAW MARROWCRUNCHER', 'A pale, lean, long-legged desert Bone-Cruncher that follows exhausted caravans and digs up shallow graves after sandstorms.', 'GRASSLAND / PLAINS', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('SALTMAW DREAD-CROC', 'A coastal saltwater Dread-Croc that patrols mangroves, reefs, and harbor mouths; feared more than sharks because it learns boat routes.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('SAND MOUSE', 'A small nocturnal rodent of the desert floor. Extremely fast. Primary prey for desert predators. Known to carry water reserves in specialized internal pouches.', 'DESERT', 'SMALLER / GAME', 'Elemental', 'global'),
('SAND RAUK', 'Desert. A desert-dwelling tawny-plumed rauk that glides over shifting dunes; a silent observer and omen of hidden oases or approaching sandstorms.', 'THE RAUK THEORY', null, 'Elemental', 'global'),
('SAND WYRM', 'A massive subterranean predator of deep desert. Detects vibration through sandy ground. Surfaces explosively to engulf prey whole. The Brunar trade routes account for known Sand Wyrm territories in their scheduling. High threat. Campaign-adjacent in large specimens. - DESERT SCORPION - a sand scorpion that is known most for the feathers that can be seen on its stinger tail.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Dragon', 'global'),
('SANDHIDE GREAT-LURK', 'A twenty-foot desert monitor that buries itself beneath loose sand with only nostrils and eyes exposed; venom turns shallow bites into slow disasters.', 'DESERT', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SAPPHIRESCALE PACKRAPTOR', 'A subaquatic Packraptor variant with blue reflective scales that shimmer like moving water. Hunts near reeds, flooded trails, and shallow crossings where prey is slowed by unstable footing.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('SAVANNAH ZEBRA', 'A striped herd grazer of open country. Skittish and fast. Primary prey for large savannah predators.', 'SAVANNAH', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('SAWSPIRAL SHARK', 'A deep-sea shark with a circular whorl of serrated teeth in the lower jaw like a living saw; evolved to cut armored mollusks but known as a boat-killer that grinds along hulls until the sea comes aboard.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SCALEBACK LIGER', 'A powerful plains predator with leonine frame and scaled hide along its spine; feared for speed, strength, and relentless pursuit.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('SEA SERPENT', 'A massive ocean-going serpentine predator. Surfaces rarely. Responsible for numerous ship disappearances in deep water. Distinguished from the Murkharthomel by its lack of tentacles and preference for open-water hunting.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('SEA TURTLE (GIANT)', 'A vast, ancient sea turtle. Some specimens are old enough to have developed minor spirit-bound resonance. Considered sacred in coastal Nazari communities. Their shells occasionally serve as temporary islands for shipwrecked sailors.', 'SUBAQUATIC / OCEAN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('SERENWEN', 'Lawful Good Glacial Dragon of Paravel.', 'GREAT DRAGONS', null, 'Dragon', 'global'),
('SEWER HORROR', 'A pale, eyeless predator adapted to the water systems beneath large Soterian cities. Hunts by sound and chemical sense. Capable of emerging through drain access points. The Ashendell City Authority officially denies their existence.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('SHADOWMOTE', 'A small, shadowy creature that moves in the dark, known for its ability to blend into the background. Attempts to possess the minds of those it attacks.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SHARDBACK WOLF', 'A badlands and coastal predator with a hide studded in razor-sharp mineral shards that detach on impact, turning every charge into a spray of living shrapnel.', 'BADLANDS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SHARDBOAR', 'A boar with crystalline tusks that can shatter stone.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('SHELL GLACIER-TURTLE', 'A sea turtle the size of a small house whose shell grows coral, barnacles, reef plants, or layered ice; a surfacing specimen can overturn fishing boats, a diving one can drag anchors and dock chains into the deep.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SHORE CROCODILIAN', 'A smaller coastal variant of the marsh crocodilian. Known to pursue prey onto dry land for short distances.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SLEET CUR', 'A tundra and arctic hunter whose ice-crusted coat and freezing breath blend into blizzards, wearing down prey with relentless cold and sleet before the final strike.', 'TUNDRA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SMILODON', 'Saber-toothed apex predators of the tundra. Hooved, enormous, and relentless.', 'TUNDRA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SNOW HARE', 'A white-furred hare of the tundra. Extremely fast. Primary prey for most tundra predators. Their burrow systems are used by travelers as emergency shelter in blizzards.', 'TUNDRA', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('SOVEREIGN MILITARY', 'The armed forces of the Sovereign Kingdom. Professional soldiers with standardized equipment and organized command. High threat.', 'FACTION THREAT GROUPS', null, 'Humanoid', 'global'),
('SPARK MOTH', 'A small moth attracted to Grid discharge points and active electrical infrastructure. In large swarms near active Grid nodes their collective wing interference can disrupt sensitive instruments and telegraph equipment.', 'INDUSTRIAL / VEINRUNNER ERA', 'SMALLER / GAME', 'Beast', 'global'),
('SPHINX', 'A cunning lion-bodied guardian of sunslit ruins, known for riddles, patience, and sudden violence. Found wherever ancient ruins exist.', 'UBIQUITOUS / CROSS-BIOME', null, 'Beast', 'global'),
('SPHYNX', 'A cunning lion-bodied guardian of sunslit ruins, known for riddles, patience, and sudden violence.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('SPIRALHORN DRILL-RHINO', 'A colossal grazing beast with a massive spiral horn used to bore into frozen ground, clay banks, root beds, and mineral deposits; charges twist and throw rather than simply impale. Prospectors follow old Spiralhorn trails hoping to find unearthed metals or crystal seams.', 'EXPANDED / MISCELLANEOUS', null, 'Elemental', 'global'),
('SPORE BEETLE', 'A slow-moving armored insect that releases defensive spore clouds when threatened. Not dangerous alone. In groups of ten or more the spore concentration causes disorientation and respiratory distress.', 'FUNGAL FOREST', 'SMALLER / GAME', 'Beast', 'global'),
('SPOREFELL OGRE', 'Fungal Forest. A hulking fungal brute that spreads choking spores and rot with every lumbering step.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('SPOREWALKER', 'A passive fungal biped that shuffles through spore-heavy groves tending older growth. Not intelligent in any recognizable way but responds to distress signals from the Mycid communal network.', 'FUNGAL FOREST', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('SPRITE', 'A cruel lesser Fae that weaponizes beauty, tricks, stolen names, and tiny acts of malice into lasting harm.', 'HUMANOID THREAT LINEAGES', null, 'Fey', 'global'),
('STALACTITE HORROR', 'A predator that clings motionless to cave ceilings disguised as natural rock formations. Drops onto prey below. Its grip prevents normal escape once contact is made. Low threat individually, extremely dangerous in groups.', 'CAVERNOUS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('STEELNEEDLE WASP', 'An eagle-sized ancient dragonfly with a metallic exoskeleton and a hardened proboscis capable of punching through leather and mail gaps; drawn to heat, blood, standing water, and bright movement. The whining hum is often worse than the strike.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('STEPPE OGRE', 'Savannah. A suns-baked nomadic giant with incredible stamina; doesn''t sprint but jogs tirelessly until prey collapses from exhaustion and heat.', 'THE OGRE EVOLUTION THEORY', null, 'Humanoid', 'global'),
('STILLMERE DREAD-CROC', 'A broader, darker lake Dread-Croc infamous for striking from beneath perfectly calm water in flooded ruins.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('STILLSTONE GOLEM', 'Still-aligned construct of cold stone, frost-veined metal, and unmoving dust. The air around it becomes muted and slow, turning motion into effort.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('STONE EAGLE', 'A large raptor of the high peaks with talons strong enough to grip sheer rock faces. Non-aggressive toward creatures it cannot carry. Their feathers are valuable trade items.', 'MOUNTAIN', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('STORMHAWK', 'A large raptor that hunts during electrical storms, riding lightning-charged updrafts with unusual physical tolerance for electrical discharge. Attacks are preceded by the smell of ozone.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('STORMRIB RAZORGALE', 'A dark-membrane tundra pterosaur that hunts before storms; its calls are often mistaken for wind tearing through rigging.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('SUMMIT WARG', 'A massive high-peak titan whose howls echo like avalanches, driving prey off cliffs and narrow ledges with cold, calculating pack tactics.', 'MOUNTAIN', 'AGGRESSIVE / PREDATORY', 'Titan', 'global'),
('SUMP CRAWLER', 'A large pale predator that inhabits the drainage sumps beneath active grimrite processing facilities. Feeds on waste organic material and anything that falls in. Eyeless. Chemically sensitive. Extremely aggressive when its sump is disturbed.', 'INDUSTRIAL / VEINRUNNER ERA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SUNBLADDER CLOUD-VULTURE', 'A pale-winged desert Cloud-Vulture that follows caravans, knowing drought will eventually choose someone.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('SUNSAIL SKINK', 'A small desert and island reptile with a bright fan-shaped sail that flushes with color to signal temperature, stress, courtship, or warning; used by travelers as a living weather sign. A frightened Sunsail sheds musk that ruins clothes for days.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('SUNSBACK ORANGUTAN', 'A broad-shouldered grassland ape with suns-warmed fur and immense strength; known for wary intelligence and dominance over scrub and tallgrass.', 'GRASSLAND / PLAINS', 'SMALLER / GAME', 'Beast', 'global'),
('SUNWROUGHT GOLEM', 'Solar-aligned construct of gold-bronze plates and sun-dial markings. Its core brightens in the presence of deception, corruption, or broken oaths.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('SWAMP RAUK', 'Marsh/Swamp. A black-feathered marsh rauk that drifts low over still water and reedbeds; feared as a grim sign by those who know the fen.', 'THE RAUK THEORY', null, 'Elemental', 'global'),
('SWAMP SNAKE', 'A semi-aquatic constrictor of shallow fen water. Mildly venomous. Bites cause localized inflammation and minor disorientation.', 'MARSH / SWAMP', 'SMALLER / GAME', 'Elemental', 'global'),
('TALLSTRIDE TITAN-HOPPER', 'A towering single-toed leaping grazer with the hind strength of a kangaroo and the long watchful face of a deer; when cornered, a kick can cave shields or launch a wolf across a ravine. Nomads follow herds as guides to clean water and stable ground.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Titan', 'global'),
('TAWNYROOT SHAGGYSWINE', 'Possesses shorter tan wool and stronger legs, making it better suited for open country. Common among caravan farmers and agrarian communities.', 'EXPANDED / MISCELLANEOUS', null, 'Beast', 'global'),
('THALORAK', 'A towering crystalline giant whose body consists of immense multi-hued mineral formations threaded with natural resonance channels. Slow-moving and seemingly passive. Some cultures believe they are living geological memory-keepers of Soteria itself.', 'CRYSTALLINE / RESONANCE-AFFLICTED', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('THE ALDERMORE GIANT', 'See Veldt Ogre entry. Distinguished from ordinary Veldt Ogres by scale and apparent age. Has not moved from its known territory in recorded history. The territory has changed around it three times.', 'NAMED / UNIQUE CREATURES', null, 'Humanoid', 'global'),
('THE GREY ONE', 'A smokey grey shoulder-up silhouette bearing the form of a classic bearded wizard beneath a vast old-world hat. His body is half-presence, half-vapor, dissolving into cold mist and pale runic fragments that drift through the air like broken geometry. His face is mostly hidden beneath shadow, beard, and brim, giving him the ancient gravity of a sage who has stepped beyond ordinary mortality. He fuses traditional wizardry with a cold, geometric, Witness-like ethereal presence: silent, architectural, distant, and unnaturally precise. Often encountered in dark cave biomes lit by ghostly fungi or faint subterranean glow, he appears less summoned than discovered, as though the cave itself has exposed a wound between realms. The Grey One''s soul is now tied to FUBIN, a realm not yet understood. Whether FUBIN is an afterlife, prison, engine, dream-plane, or unfinished world remains unknown. Since the binding, he no longer exists entirely in one place; his body smokes, fractures, and reforms, while the symbols around him may be pieces of his soul leaking through from that strange realm. Threat Level: Unknown / Campaign-adjacent. Resonance: Echoing, Glyphic, Fubin-Bound.', 'UBIQUITOUS / CROSS-BIOME', null, 'Undead', 'global'),
('THE MURKHARTHOMEL OF THE SUNKEN ROAD', 'A specific Murkharthomel that has claimed the underwater channel between two major port cities as its territory. Named in Nazari shipping records as the primary cause of the Sunken Road being considered impassable. Campaign-level threat. Several expeditions have attempted to clear it. None have reported back definitively.', 'NAMED / UNIQUE CREATURES', null, 'Elemental', 'global'),
('THE PATIENT ONE', 'A Grimrite Wolf of extraordinary age and size whose pack has inhabited the Corren Mountain Mine collapse zone for generations. Has reached a state of crystalline calm. Does not rush. Does not waste movement. Has killed eleven documented expeditions and is believed to be waiting for something specific, though no scholar has survived long enough to determine what.', 'NAMED / UNIQUE CREATURES', null, 'Beast', 'global'),
('THE WHISPERING FROSTWRAITH OF THE FALORN FJORDS', 'A near-Titan scale Frostwraith that has inhabited the Falorn Fjords for longer than Ködan oral history extends. Does not hunt in the conventional sense — its presence simply makes the region lethal. Titan-adjacent threat. Do not deploy without full campaign context.', 'NAMED / UNIQUE CREATURES', null, 'Undead', 'global'),
('THICKET MOUSE', 'An unremarkable small rodent found throughout woodland Soteria. Mentioned because players ask about them constantly and they are genuinely everywhere.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('THISTLEWING', 'A woodland rabbit with winged ears and a penchant for gliding short distances between trees. Often seen flitting between branches.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('THORN FOX', 'A lean rust-colored fox with barbed guard hairs along its spine. Hunts small game and occasionally pilfers from camp supplies. Clever enough to unlatch poorly secured packs.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Elemental', 'global'),
('THORNBACK BEETLE', 'A sturdy heat-tempered insect with a heavily armored spiked shell; can launch razor-sharp thorns like projectiles to impale predators at distance.', 'VOLCANIC', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('THORNNEEDLE WASP', 'A bronze and bark-colored forest strain of Steelneedle Wasp that perches on trunks and darts through gaps in dense trees with impossible precision.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('THREADBOUND GOLEM', 'Loom-aligned construct woven from bone needles, brass spindles, knotted cord, hair, silk, and fate-scripted thread. It binds, pulls, and repositions enemies as if combat itself were a pattern to be corrected.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('TIDAL WRAITH', 'A semi-translucent aquatic predator of coastal tidal zones. Feeds on the distress resonance of drowning victims. Encourages panic rather than attacking directly. Resonance: Void-Tainted.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Undead', 'global'),
('TIDEGLASS GOLEM', 'Water-aligned construct made from blue-green glass, river stones, coral, and suspended water. Its body bends and reforms like a current, allowing it to absorb blows and force enemies into drowning grips.', 'GOLEM FAMILY', null, 'Construct', 'global'),
('TIDEGLASS PRISM-WING', 'A pearl, teal, and coral island strain of Prism-Wing; favored as court gifts but becomes melancholy if kept away from sea wind.', 'SKY', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('TIDEHIDE GREAT-LURK', 'A darker, stronger-swimming island monitor that raids nests, beaches, and fishing camps with patient precision; more tolerant of saltwater than inland strains.', 'SUBAQUATIC / OCEAN', 'AGGRESSIVE / PREDATORY', 'Elemental', 'global'),
('TIDEHOOK SCYTHE-SHRIMP', 'A red-brown-black mottled Scythe-Shrimp from tide pools and volcanic lagoons; nearly invisible against wet stone.', 'RIVER / COASTAL / FRESHWATER', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('TIGER-FLY', 'A vibrant insect with tiger-like stripes and razor-sharp mandibles; hunts in swarms capable of stripping a wounded creature to the bone in minutes.', 'JUNGLE / RAINFOREST', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('TOYTAKER', 'A small predatory horror associated with missing children, broken toys, and rooms that should not be locked from the inside. Imitates play sounds to lure victims closer before striking from cupboards, crawlspaces, or beneath beds.', 'UNDEAD', 'HAUNTED UNDEAD', 'Beast', 'global'),
('TRACKBIRD', 'A small bird that has built its ecological niche around the Veinrunner rail network. Nests in signal towers and beneath platform overhangs. Feeds on insects disturbed by train passage. Their sudden absence from a rail station is considered a bad omen by experienced conductors.', 'INDUSTRIAL / VEINRUNNER ERA', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('TRIDENT TAILED LYNX', 'A silver-furred lynx that can turn nearly invisible in shadow; its large tail splits into three.', 'GRASSLAND / PLAINS', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('TROLL OF AETHER', 'A pale radiant troll marked by faint star-like scars, luminous veins, and an unsettling nearness to spirit places. It appears near shrines, high ruins, old sanctums, and thin places where the mortal world brushes the divine. Its wounds close in flashes of white-gold light, though profane iron, Nullite, and broken rites can interrupt its restoration.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF AIR', 'A gaunt, long-limbed troll with hollow bones, wind-torn skin, and a chest that bellows like a storm vent. It hunts cliffs, high bridges, broken towers, and mountain passes, using sudden gusts and thunderous roars to unbalance prey. Its regeneration weakens in sealed spaces where the air is still and heavy.', 'TROLLS', null, 'Undead', 'global'),
('TROLL OF EARTH', 'A broad stone-backed troll with soil-packed hide, root-tangled limbs, and mineral plates across its shoulders. It sleeps half-buried in hillsides, cairns, old roads, and battlefields, rising when footsteps disturb the ground above it. Its regeneration is slow but extremely difficult to stop, knitting flesh with clay, root, and buried bone.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF FIRE', 'A heat-scarred troll with coal-dark hide, ember-lit wounds, and a furnace glow deep in its throat. It haunts burned forests, forgefields, volcanic roads, and ruined battle camps, feeding on charred meat, hot metal, and anything foolish enough to approach its lair. Its regeneration is aggressive, but cold water, smothering ash, and deprivation of air can slow the healing.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF LOOM', 'A strange troll threaded with cordlike growths, scar-patterns, and webbed strands of pale connective tissue. It is drawn to crossroads, old family holdings, oath-sites, and places where many lives have become entangled. Its regeneration follows patterns; if one wound is repeated exactly, the second cut may reopen the first.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF LUNAR', 'A moon-pale troll with reflective eyes, tide-marked skin, and a habit of appearing where dreams, sleep, and hidden paths overlap. It hunts at night along shorelines, silver marshes, old roads, and ruins touched by moonlight. Its body heals strongest under the moon, but becomes sluggish beneath harsh noon sun.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF SOLAR', 'A golden-eyed troll with cracked sunburned hide, bright scars, and a roar that sounds like stone splitting under heat. It favors open plains, temple roads, dry mesas, and exposed ruins where daylight gives it strength. Its regeneration is fastest in direct sun, but it weakens in deep shade, sealed caves, or prolonged darkness.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF SPARK', 'A restless twitching troll with bright nerves visible under the skin, snapping teeth, and sudden bursts of violent speed. It haunts workshops, storm-struck trees, ruined laboratories, and places where invention or wild life-force has gone wrong. Its regeneration is erratic, sometimes healing instantly and sometimes mutating the wound into something worse.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF STILL', 'A deathly quiet troll with waxen skin, slow breath, and glassy eyes that rarely blink. It waits motionless in frozen ponds, sealed crypts, silent ruins, and abandoned halls, sometimes mistaken for a statue or corpse until prey comes close. Its regeneration is slow but preserves it through starvation, cold, and wounds that should have ended it long ago.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF VOID', 'A black-skinned troll whose outline seems to drink lamplight and silence nearby sound. It haunts abandoned wells, collapsed underroads, dead caverns, and places where fires refuse to stay lit. Its regeneration is unnatural and partial, with missing flesh returning as cold shadow before becoming meat again.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF WATER', 'A slick blue-gray troll adapted to rivers, marshes, flood tunnels, and cold underground lakes. It waits beneath bridges, reeds, and black water, dragging prey under rather than killing quickly. Its flesh closes like wet clay, and old specimens are said to remember every voice they have drowned.', 'TROLLS', null, 'Troll', 'global'),
('TROLL OF WEIGHT', 'A massive low-slung troll with dense bones, sagging stone-thick flesh, and footsteps that make loose rock tremble. It dwells in deep valleys, pressure caverns, collapsed forts, and places burdened by old oaths or heavy grief. Its presence makes armor feel heavier and running feel harder, while its own body resists being moved, lifted, or knocked aside.', 'TROLLS', null, 'Troll', 'global'),
('TUNDRA OX', 'A massive shaggy-coated bovine of the frozen north. Domesticated by Terraxian and Ködan communities as a draft animal and food source. Their wool is among the warmest natural fiber available in Soteria.', 'TUNDRA', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('TUNDRA WOLF', 'Larger than the woodland grey wolf, adapted to extreme cold, with pale grey-white coats. Packs of up to twenty. Extremely coordinated hunters. Known to follow Smilodon kills.', 'TUNDRA', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('TUNNEL MOLE', 'A large burrowing creature used by Durinak engineering teams to locate soft soil pockets before drilling. Blind, docile, and extremely difficult to startle. Considered good luck in mining culture.', 'UNDERGROUND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('TUNNEL RAT', 'Aggressive, large, disease-carrying rodent of city sewer and cellar systems. Found everywhere. Considered the most common hazard in Ashendell''s lower districts.', 'CITY / URBAN', 'SMALLER / GAME', 'Beast', 'global'),
('TWILLWISP', 'A small luminous woodland creature that drifts through brush and branch like a living lantern.', 'WOODLAND', 'SMALLER / GAME', 'Beast', 'global'),
('TYPHON', 'The Destroyer; Titan Demon.', 'GREAT TITANS', null, 'Titan', 'global'),
('UNICORN', 'A rare horned creature of untouched glades, tied to calm and purity.', 'WOODLAND', 'DOCILE / FRIENDLY', 'Beast', 'global'),
('VALVE-WHALE', 'A massive gas-filled cephalopod that drifts through chemical clouds, filtering toxins and occasionally providing "islands" of buoyant safety for weary travelers.', 'BADLANDS', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('VEINSPINNER', 'A mechanized arachnid that weaves intricate webs of glowing threads. Formidable in combat, using its mechanical limbs to strike with precision and power.', 'CITY / URBAN', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('VEK''AR', 'A small humanoid figure with glowing eyes found in the Altum (Heaven planes).', 'COSMIC / VOID / ASTRAL', 'DOCILE / FRIENDLY', 'Humanoid', 'global'),
('VELDT OGRE / THE ALDERMORE GIANT', 'Grassland/Plains. A massive monolithic titan with weathered stone-like skin cracked by the relentless glare of the three suns; a jagged sentinel over scorched open country.', 'THE OGRE EVOLUTION THEORY', null, 'Titan', 'global'),
('VENOMHIDE GREAT-LURK', 'A twenty-foot monitor lizard with venom that turns shallow bites into slow disasters; strikes once, withdraws, and follows wounded prey until venom, infection, and exhaustion do the work. "The ground is listening" means a Great-Lurk is nearby.', 'SAVANNAH', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('VESSEL', 'A Dybuk-Host in late stage who has been in that state long enough to develop independent goals beyond simple feeding. The original host was someone significant enough that their memory and the Dybuk''s hunger have merged into something new. Can pass as human in dim light. Campaign-level threat.', 'NAMED / UNIQUE CREATURES', null, 'Fiend', 'global'),
('VESUVIAN PACKRAPTOR', 'A heat-hardened Packraptor variant with dark basalt scales and ember-colored throat markings. Its packs drive prey toward unstable ground, ash clouds, and choking smoke.', 'VOLCANIC', 'AGGRESSIVE / PREDATORY', 'Beast', 'global'),
('VOID RAUK', 'Cosmic/Void. A gaunt shadow-slicked rauk with pitch-black plumage that absorbs all light; a soul-chilling omen that circles over those marked for consumption by the Void.', 'THE RAUK THEORY', null, 'Fiend', 'global'),
('VOLTAIC GOLEM', 'Spark-aligned construct of copper, iron, glass coils, magnetized plates, and storm-captured lightning. Its movements are sharp, twitching, and violently sudden.', 'GOLEM FAMILY', null, 'Construct', 'global'),
